form:Form.form:Scripts:
		var MyNOVSel=null;
var Edit=false;
var New=false;

function RefreshControls()
{
	//Desactivo los Controles de Cambio
	if (MyNOVSel==null)
	{
		CtrlEnabled("DATA"  , false);
		CtrlEnabled("ADD"   , true );
		CtrlEnabled("EDIT"  , false);
		CtrlEnabled("DELETE", false);
		CtrlEnabled("BACK"  , true );
		CtrlEnabled("ACCEPT", false);
		CtrlEnabled("CANCEL", false);
	} else 
	if (Edit)
	{
		CtrlEnabled("DATA"  , true );
		CtrlEnabled("ADD"   , false);
		CtrlEnabled("EDIT"  , false);
		CtrlEnabled("DELETE", false);
		CtrlEnabled("BACK"  , false);
		CtrlEnabled("ACCEPT", true );
		CtrlEnabled("CANCEL", true );
	} else
	{
		CtrlEnabled("DATA"  , false);
		CtrlEnabled("ADD"   , true );
		CtrlEnabled("EDIT"  , true );
		CtrlEnabled("DELETE", true );
		CtrlEnabled("BACK"  , true );
		CtrlEnabled("ACCEPT", false);
		CtrlEnabled("CANCEL", false);
	}
}


function RefreshCustomDay(MyOBJ, mydate)
{    
	var t, MyROW, newval, ff, he, hs;

	//Novedades
	for (t=0; t<Ctrl("arrNovedades").CountRow(); t++)
	{
		MyROW=Ctrl("arrNovedades").GetRow(t);

		if (MyNOVSel==null || MyROW.GetAttr("id")!=MyNOVSel.GetAttr("id"))                  
		{
			ff=MyROW.GetAttr("f_fecha");		
			he=parseInt(MyROW.GetAttr("e_horainicio"),10);
			hs=parseInt(MyROW.GetAttr("e_horafin"),10);
		  horfound=MyHOR[MyROW.GetAttr("oi_tipohora")];
	  } else
	  {
			ff=Ctrl("f_fecha").GetXValue();		
			he=parseInt(Ctrl("e_horainicio").GetXValue(),10);
			hs=parseInt(Ctrl("e_horafin").GetXValue(),10);
		  horfound=MyHOR[Ctrl("oi_tipohora").GetXValue()];
	  }
		if (ff!=mydate) continue;

		newval=MyOBJ.SetValue(
			ff,
			he,
			hs,
			"Novedad: "+horfound.label,
			horfound.color,
			horfound.color,
			"Novedad: "+horfound.label+" desde "+int2time(he)+" a "+int2time(hs),
			"BAR"
		);    

		newval.MyID    =MyROW.GetAttr("id");
		newval.selected=MyNOVSel?((MyROW.GetAttr("id")==MyNOVSel.GetAttr("id"))?true:false):false;
	}
}

function OnClickHorario(obj, dte, value)
{      
	var MyROW, dme;
	if (value.MyID?false:true) return;
	if (Edit) return;   

	MyROW=Ctrl("arrNovedades").GetRowByAttr("id", value.MyID);
	Ctrl("f_fecha"      ).SetXValue(MyROW.GetAttr("f_fecha"      ));
	Ctrl("e_horainicio" ).SetXValue(MyROW.GetAttr("e_horainicio" ));
	Ctrl("e_horafin"    ).SetXValue(MyROW.GetAttr("e_horafin"    ));
	Ctrl("oi_tipohora"  ).SetXValue(MyROW.GetAttr("oi_tipohora"  ));
	Ctrl("d_novedad"    ).SetXValue(MyROW.GetAttr("d_novedad"    ));
	Ctrl("oi_estructura").SetXValue(MyROW.GetAttr("oi_estructura"));
	Ctrl("o_novedad"    ).SetXValue(MyROW.GetAttr("o_novedad"    ));
	Ctrl("d_fecha"      ).SetXValue(formatdatetime2str(MyROW.GetAttr("f_fecha"), "YYYYMMDD", "/", "")+" desde "+int2time(parseInt(MyROW.GetAttr("e_horainicio")))+" hasta "+int2time(parseInt(MyROW.GetAttr("e_horafin"))));

 	var daylist=new Array();	
	if (MyNOVSel!=null && MyNOVSel.GetAttr("f_fecha")!=MyROW.GetAttr("f_fecha")) 
		daylist.push(MyNOVSel.GetAttr("f_fecha"));

	MyNOVSel=MyROW;
	daylist.push(MyNOVSel.GetAttr("f_fecha"));
	ReDrawWait(MyOBJ, daylist, true, true);
	New=false;
}

function AddNovedad()
{
	NomadTimeout("internalAddNovedad();",100,"Generando la Novedad...");
}

function internalAddNovedad()
{       
	var dme;                         
	var newDate=new Date();
	MyROW=Ctrl("arrNovedades").AddRow();
	MyROW.SetAttr("id"           ,"#"+datetime2str(newDate));
	MyROW.SetAttr("f_fecha"      ,"");
	MyROW.SetAttr("e_horainicio" ,"");
	MyROW.SetAttr("e_horafin"    ,"");
	MyROW.SetAttr("oi_tipohora"  ,MyHORDef.id);
	MyROW.SetAttr("d_novedad"    ,"");
	MyROW.SetAttr("oi_estructura","");
	MyROW.SetAttr("o_novedad"    ,"");

	Ctrl("f_fecha"      ).SetXValue(MyROW.GetAttr("f_fecha"      ));
	Ctrl("e_horainicio" ).SetXValue(MyROW.GetAttr("e_horainicio" ));
	Ctrl("e_horafin"    ).SetXValue(MyROW.GetAttr("e_horafin"    ));
	Ctrl("oi_tipohora"  ).SetXValue(MyROW.GetAttr("oi_tipohora"  ));
	Ctrl("d_novedad"    ).SetXValue(MyROW.GetAttr("d_novedad"    ));
	Ctrl("oi_estructura").SetXValue(MyROW.GetAttr("oi_estructura"));
	Ctrl("o_novedad"    ).SetXValue(MyROW.GetAttr("o_novedad"    ));
	Ctrl("d_fecha"      ).SetXValue("");


 	var daylist=new Array();	
	if (MyNOVSel!=null && MyNOVSel.GetAttr("f_fecha")!=MyROW.GetAttr("f_fecha")) 
		daylist.push(MyNOVSel.GetAttr("f_fecha"));

	MyNOVSel=MyROW;
	StartEdit();
	New=true;

	ReDrawWait(MyOBJ, daylist, true, true);
} 

function DelNovedad()
{  
	//Verifico si el dia esta bloqueado
	if (MyOBJ.Locks[MyNOVSel.GetAttr("f_fecha")])
	{
		alert("No se puede modificar.\r\n"+MyOBJ.Locks[MyNOVSel.GetAttr("f_fecha")]);
		return false;
	}

	var ff=MyNOVSel.GetAttr("f_fecha");                                      
	var daylist=new Array();

	Ctrl("arrNovedades").DelRowByAttr("id", MyNOVSel.GetAttr("id"));

	MyNOVSel=null; daylist.push(ff);
	ReDrawWait(MyOBJ, daylist, true, true);
}

function StartEdit()
{       
	//Verifico si el dia esta bloqueado
	if (MyOBJ.Locks[MyNOVSel.GetAttr("f_fecha")])
	{
		alert("No se puede modificar.\r\n"+MyOBJ.Locks[MyNOVSel.GetAttr("f_fecha")]);
		return false;
	}

  var horfound=MyHOR[MyNOVSel.GetAttr("oi_tipohora")];
	Edit=true;

  if (horfound)
  {
		MyOBJ.EditStart();           
		MyOBJ.SelectStyle(horfound.color,"TIME");
  } else
  {
		MyOBJ.EditStart();           
		MyOBJ.SelectStyle("000000","BAR");
  }

	RefreshControls();     
}          

function EditCancel()
{         
	var ff1=Ctrl("f_fecha").GetXValue();
	var ff2=MyNOVSel.GetAttr("f_fecha");

	var daylist=new Array();
	if (New)
	{
		Ctrl("arrNovedades").DelRowByAttr("id", MyNOVSel.GetAttr("id"));
		MyNOVSel=null;
	} else
	{
		Ctrl("f_fecha"      ).SetXValue(MyNOVSel.GetAttr("f_fecha"      ));
		Ctrl("e_horainicio" ).SetXValue(MyNOVSel.GetAttr("e_horainicio" ));
		Ctrl("e_horafin"    ).SetXValue(MyNOVSel.GetAttr("e_horafin"    ));
		Ctrl("oi_tipohora"  ).SetXValue(MyNOVSel.GetAttr("oi_tipohora"  ));
		Ctrl("d_novedad"    ).SetXValue(MyNOVSel.GetAttr("d_novedad"    ));
		Ctrl("oi_estructura").SetXValue(MyNOVSel.GetAttr("oi_estructura"));
		Ctrl("o_novedad"    ).SetXValue(MyNOVSel.GetAttr("o_novedad"    ));
		Ctrl("d_fecha"      ).SetXValue(formatdatetime2str(MyNOVSel.GetAttr("f_fecha"), "YYYYMMDD", "/", "")+" desde "+int2time(MyNOVSel.GetAttr("e_horainicio"))+" hasta "+int2time(MyNOVSel.GetAttr("e_horafin")));
		MyNOVSel=null;
	}
	Edit=false;
	New=false;

	MyOBJ.EditEnd();
	RefreshControls();

	if (ff1!="") daylist.push(ff1);
	if (ff2!="" && ff1!=ff2) daylist.push(ff2);
	ReDrawWait(MyOBJ, daylist, true, false);
}       

function ChangeTime(obj, dte, timestart, timeend)
{                           
	var lastdte=Ctrl("f_fecha").GetXValue();
	var daylist=new Array();

	Ctrl("f_fecha"      ).SetXValue(dte);                
	Ctrl("e_horainicio" ).SetXValue(timestart);
	Ctrl("e_horafin"    ).SetXValue(timeend);
	Ctrl("d_fecha"      ).SetXValue(formatdatetime2str(dte, "YYYYMMDD", "/", "")+" desde "+int2time(timestart)+" hasta "+int2time(timeend));

	if ((lastdte!=dte) && (lastdte!="")) daylist.push(lastdte); 
	daylist.push(dte);
	ReDrawWait(MyOBJ, daylist, true, false);
}

function EditAccept()
{    
	var t;

	var sd=Math.floor((str2date(Ctrl("f_fecha").GetXValue())-str2date("20000102"))/60000);
	var ds=sd+parseInt(Ctrl("e_horainicio").GetXValue(),10);
	var de=sd+parseInt(Ctrl("e_horafin").GetXValue(),10);

	var sd_check;
	var ds_check;
	var de_check;

	var myDate,MyHopeDay;

	//Verifico si el dia esta bloqueado
	if (MyOBJ.Locks[Ctrl("f_fecha").GetXValue()])
	{
		alert("No se puede modificar.\r\n"+MyOBJ.Locks[Ctrl("f_fecha").GetXValue()]);
		return false;
	}


  //Veririco las Novedades
	for (t=0; t<Ctrl("arrNovedades").CountRow(); t++)
	{
		MyROW=Ctrl("arrNovedades").GetRow(t);
		if (MyROW.GetAttr("id")==MyNOVSel.GetAttr("id")) continue;

		sd_check=Math.floor((str2date(MyROW.GetAttr("f_fecha"))-str2date("20000102"))/60000);
		ds_check=sd_check+parseInt(MyROW.GetAttr("e_horainicio"),10);
		de_check=sd_check+parseInt(MyROW.GetAttr("e_horafin"),10);

		if (ds_check>=de) continue;
		if (de_check<=ds) continue;

		alert("La Novedad modificada se superpone con otra novedad.");
		return false;
	}

	//Verifico contra la esperanza                                             
	myDate=str2date(Ctrl("f_fecha").GetXValue());
	myDate.setDate(myDate.getDate()-1);
	MyHopeDay=GetHope(Math.floor((myDate-str2date("20000102"))/604800000)).FindElement2("DIA","f_dia",date2str(myDate));

  sd_check=Math.floor((myDate-str2date("20000102"))/60000);
	if (MyHopeDay!=null)
	for (cur=MyHopeDay.FindElement("DETALLE").FirstChild(); cur!=null; cur=cur.Next())
	{            
		ds_check=sd_check+parseInt(cur.GetAttr("e_horainicio"),10);
		de_check=sd_check+parseInt(cur.GetAttr("e_horafin"),10);

		if (ds_check>=de) continue;
		if (de_check<=ds) continue;

		alert("La Novedad modificada se superpone con una esperanza del dia anterior.");
		return false;
	}

	//Verifico contra la esperanza                                             
	myDate=str2date(Ctrl("f_fecha").GetXValue());
	myDate.setDate(myDate.getDate()+1);
	MyHopeDay=GetHope(Math.floor((myDate-str2date("20000102"))/604800000)).FindElement2("DIA","f_dia",date2str(myDate));

  sd_check=Math.floor((myDate-str2date("20000102"))/60000);
	if (MyHopeDay!=null)
	for (cur=MyHopeDay.FindElement("DETALLE").FirstChild(); cur!=null; cur=cur.Next())
	{            
		ds_check=sd_check+parseInt(cur.GetAttr("e_horainicio"),10);
		de_check=sd_check+parseInt(cur.GetAttr("e_horafin"),10);

		if (ds_check>=de) continue;
		if (de_check<=ds) continue;

		alert("La Novedad modificada se superpone con una esperanza del dia posterior.");
		return false;
	} 

 	NomadTimeout("internalEditAccept();",100,"Actualizando la vista...");
}                                 

function internalEditAccept()
{
	MyNOVSel.SetAttr("f_fecha"      , Ctrl("f_fecha"      ).GetXValue());
	MyNOVSel.SetAttr("e_horainicio" , Ctrl("e_horainicio" ).GetXValue());
	MyNOVSel.SetAttr("e_horafin"    , Ctrl("e_horafin"    ).GetXValue());
	MyNOVSel.SetAttr("oi_tipohora"  , Ctrl("oi_tipohora"  ).GetXValue());
	MyNOVSel.SetAttr("d_novedad"    , Ctrl("d_novedad"    ).GetXValue());
	MyNOVSel.SetAttr("oi_estructura", Ctrl("oi_estructura").GetXValue());
	MyNOVSel.SetAttr("o_novedad"    , Ctrl("o_novedad"    ).GetXValue());
	Edit=false;
	New=false;

	MyOBJ.EditEnd();  
	OnChangePeriodo();
	RefreshControls();     
}
